const aiOutput = items[0].json.output || items[0].json.text || items[0].json.message?.content;
const dataAtual = new Date().toLocaleDateString('pt-BR');

function formatarNewsletter(texto) {
    if (!texto) return "Gerando inteligência corporativa...";

    // Limpeza de caracteres especiais e numerações
    let limpo = texto.replace(/[*#]/g, '')
                     .replace(/^[ \t]*[-•][ \t]*/gm, '')
                     .replace(/^[ \t]*\d+[.)][ \t]*/gm, '');

    return limpo
        // Início do Card da Notícia (Arredondado)
        .replace(/CATEGORIA: (.*)/gi, '<div style="background: #0a0a0a; border: 1px solid #1a1a1a; padding: 25px; border-radius: 20px; margin-bottom: 30px;">' +
            '<div style="display: inline-block; background: #2a1b3d; color: #bb86fc; padding: 5px 15px; border-radius: 50px; font-size: 10px; font-weight: bold; letter-spacing: 1px; border: 1px solid #44315d; text-transform: uppercase; margin-bottom: 15px;">$1</div>')

        // Título
        .replace(/TITULO: (.*)/gi, '<h2 style="color: #ffffff; font-size: 20px; margin: 0 0 12px 0; line-height: 1.3; font-weight: 700;">$1</h2>')

        // Contexto (Justificado e Branco)
        .replace(/CONTEXTO: (.*)/gi, '<p style="text-align: justify; color: #ffffff; font-size: 14px; margin-bottom: 12px; line-height: 1.6; font-weight: 300;">$1</p>')

        // Impacto (Branco e Negrito)
        .replace(/IMPACTO: (.*)/gi, '<p style="text-align: justify; color: #ffffff; font-size: 14px; margin-bottom: 20px; line-height: 1.6;"><strong>ANÁLISE:</strong> $1</p>')

        // Botão de Fonte (Arredondado)
        .replace(/FONTE: (.*)/gi, '<a href="$1" style="color: #ff79c6; text-decoration: none; font-size: 11px; font-weight: bold; text-transform: uppercase; border: 1px solid #ff79c6; padding: 8px 18px; border-radius: 50px; display: inline-block;">Ver Notícia</a></div>')

        // Seção de Tendências (Card com borda Roxa Arredondada)
        .replace(/ANALISE DE TENDENCIAS: (.*)/gi, '<div style="background: #120a1f; padding: 30px; border-radius: 25px; border: 1px solid #6200ee; margin-top: 40px;"><h3 style="color: #bb86fc; margin: 0 0 20px 0; font-size: 18px; letter-spacing: 2px; text-align: center; text-transform: uppercase;">Tendências & Padrões</h3><p style="text-align: justify; color: #ffffff; font-size: 14px; line-height: 1.8; margin: 0;">$1</p>')

        // Insight Academy (Borda arredondada interna)
        .replace(/INSIGHT ACADEMY: (.*)/gi, '<div style="margin-top: 25px; padding: 20px; border-radius: 15px; border-left: 5px solid #bb86fc; background: #1a1a1a;"><p style="text-align: justify; color: #ffffff; font-size: 13px; margin: 0; line-height: 1.6;"><strong>ESTUDO RECOMENDADO:</strong> $1</p></div></div>')

        .replace(/\n/g, '');
}

const htmlFinal = `
<div style="background-color: #000000; color: #ffffff; font-family: 'Segoe UI', Roboto, Helvetica, sans-serif; padding: 50px 20px; max-width: 600px; margin: auto;">
    <header style="text-align: center; margin-bottom: 50px;">
        <div style="display: inline-block; background: #6200ee; color: #ffffff; padding: 4px 12px; border-radius: 50px; font-size: 9px; font-weight: bold; letter-spacing: 3px; text-transform: uppercase; margin-bottom: 20px;">INTELI ACADEMY</div>
        <h1 style="color: #ffffff; font-size: 32px; margin: 0; font-weight: 800; letter-spacing: -1px;">Intelligence <span style="color: #bb86fc;">Newsletter</span></h1>
        <div style="color: #ffffff; font-size: 10px; margin-top: 15px; opacity: 0.7; letter-spacing: 1px;">EDIÇÃO #01 • ${dataAtual}</div>
    </header>

    <main>
        ${formatarNewsletter(aiOutput)}
    </main>

    <footer style="margin-top: 80px; text-align: center; border-top: 1px solid #1a1a1a; padding-top: 40px;">
        <p style="color: #6200ee; font-size: 10px; font-weight: bold; letter-spacing: 2px; text-transform: uppercase; margin: 0;">
            Curadoria Autônoma de Alta Performance
        </p>
    </footer>
</div>
`;

return [{ json: { corpo_email: htmlFinal } }];
